						}},
						{"storedSource", true}, // or false, or bson.D{{"include", bson.A{"<field-name>", /* ... */}}} or bson.D{{"exclude", bson.A{"<field-name>", /* ... */}}}
					}},
					// ... additional fields
				}},
			}},
