				bson.D{
					{"name", "<type-set-name>"},
					{"types", bson.A{
						bson.D{
							{"type", "<field-type>"},
							// ... additional field type configuration
						},
						// ... additional types
					}},
				},
				// ... additional typeSets
			}},
		},
