        "createSearchIndexes" : collection,
        "indexes" : [ {
          "name" : "default",
          "definition" : {
            "mappings": {
              "dynamic": false,
              "fields": {
                "relationships": {
                  "type": "embeddedDocuments",
                  "dynamic": {
                    "typeSet": "stringBooleanIndex"
                  },
