The following index example disables dynamic mappings at the root level
and uses static mappings to index the `relationships` field as the
`embeddedDocuments` type. It also applies the configured
`stringBooleanIndex` `typeSet` to index only the `string` and
`boolean` types the `relationships` array of objects. It applies the
`stringBooleanIndex` `typeSet` to the nested `person` document to
index only the `boolean` and `string` types in the `person`
document.

```cpp
#include <iostream>

#include <bsoncxx/builder/basic/document.hpp>
#include <bsoncxx/json.hpp>
#include <mongocxx/client.hpp>
#include <mongocxx/instance.hpp>
#include <mongocxx/uri.hpp>

using bsoncxx::builder::basic::kvp;
using bsoncxx::builder::basic::make_document;

int main() {
    // Initialize the MongoDB C++ driver
    mongocxx::instance instance{};

    // Connect to your MongoDB deployment
    mongocxx::uri uri("<connection-string>");
    mongocxx::client client(uri);

    auto db = client["sample_training"];
    auto collection = db["companies"];
    auto siv = collection.search_indexes();

    // Create the Atlas Search index definition for the embeddedDocuments field with dynamic mapping
    auto name = "default";
    auto definition = make_document(
        kvp("mappings", make_document(
            kvp("dynamic", false),
            kvp("fields", make_document(
                kvp("relationships", make_document(
                    kvp("type", "embeddedDocuments"),
                    kvp("dynamic", make_document(
                        kvp("typeSet", "stringBooleanIndex")
                    )),
                    kvp("fields", make_document(
                        kvp("person", make_document(
                            kvp("type", "document"),
                            kvp("dynamic", make_document(
                                kvp("typeSet", "stringBooleanIndex")
                            ))
                        ))
                    ))
                ))
            ))
        )),
        kvp("typeSets", []{
            auto arr = bsoncxx::builder::basic::array{};
            arr.append(make_document(
                kvp("name", "stringBooleanIndex"),
                kvp("types", []{
                    auto types_arr = bsoncxx::builder::basic::array{};
                    types_arr.append(make_document(kvp("type", "boolean")));
                    types_arr.append(make_document(kvp("type", "string")));
                    return types_arr;
                }())
            ));
            return arr;
        }())
    );
    auto model = mongocxx::search_index_model(name, definition.view());

    try {
        // Execute the command to create the index
        auto result = siv.create_one(model);
        std::cout << "New index name: " << result << std::endl;
    } catch (const std::exception& e) {
        std::cerr << "Error creating Atlas Search index: " << e.what() << std::endl;
    }

}
```

